// C solution (uses fast I/O and a segment tree for point location)
#include <stdio.h>
#include <stdlib.h>

typedef struct {int x1,y1,x2,y2,idx;int parent;int depth;} Rect;

// Simple dynamic array for rectangles
static Rect *rects; static int rectCnt=0, rectCap=0;
static void addRect(int x1,int y1,int x2,int y2){
    if(rectCnt==rectCap){rectCap=rectCap?rectCap*2:1024; rects=(Rect*)realloc(rects,rectCap*sizeof(Rect));}
    rects[rectCnt].x1=x1; rects[rectCnt].y1=y1; rects[rectCnt].x2=x2; rects[rectCnt].y2=y2; rects[rectCnt].idx=rectCnt+1; rects[rectCnt].parent=0; rects[rectCnt].depth=0; rectCnt++;}

// Segment tree node stores ids of rectangles that completely cover the node's x‑range
typedef struct Node{int l,r;int *ids;int idCnt;int idCap;} Node;
static Node *seg; static int segSize;
static void segInit(int n){int sz=1;while(sz<n)sz<<=1; segSize=sz*2; seg=(Node*)calloc(segSize,sizeof(Node));}
static void segAdd(int node,int l,int r,int ql,int qr,int id){if(ql>r||qr<l) return; if(ql<=l && r<=qr){Node *nd=&seg[node]; if(nd->idCnt==nd->idCap){nd->idCap=nd->idCap?nd->idCap*2:4; nd->ids=(int*)realloc(nd->ids, nd->idCap*sizeof(int));} nd->ids[nd->idCnt++]=id; return;} int mid=(l+r)/2; segAdd(node*2,l,mid,ql,qr,id); segAdd(node*2+1,mid+1,r,ql,qr,id);}

// Find deepest rectangle containing point (x,y)
static int queryPoint(int node,int l,int r,int x,int y){int ans=0; Node *nd=&seg[node]; for(int i=0;i<nd->idCnt;i++){
        Rect *rc=&rects[nd->ids[i]-1];
        if(rc->y1<=y && y<=rc->y2){ans=rc->idx;}
    }
    if(l==r) return ans; int mid=(l+r)/2; if(x<=mid) {int sub=queryPoint(node*2,l,mid,x,y); if(sub) ans=sub;} else {int sub=queryPoint(node*2+1,mid+1,r,x,y); if(sub) ans=sub;} return ans;}

int main(){int N,M,Q; if(scanf("%d %d %d",&N,&M,&Q)!=3) return 0; rects=NULL; rectCnt=0; rectCap=0;
    // store events for later processing
    int *type=(int*)malloc(Q*sizeof(int));
    int (*ev)[4]=(int(*)[4])malloc(Q*4*sizeof(int));
    for(int i=0;i<Q;i++){
        scanf("%d %d %d %d %d",&type[i],&ev[i][0],&ev[i][1],&ev[i][2],&ev[i][3]);
        if(type[i]==1) addRect(ev[i][0],ev[i][1],ev[i][2],ev[i][3]);
    }
    // build segment tree on x‑range 1..N
    segInit(N);
    for(int i=0;i<rectCnt;i++) segAdd(1,1,N,rects[i].x1,rects[i].x2,rects[i].idx);
    // answer queries
    for(int i=0;i<Q;i++) if(type[i]==2){
        int a=queryPoint(1,1,N,ev[i][0],ev[i][1]);
        int b=queryPoint(1,1,N,ev[i][2],ev[i][3]);
        if(a==b) printf("YES\n"); else printf("NO\n");
    }
    return 0; }
